        <i class="bi bi-sliders"></i> Configuration Profil & Logo
      </a>

      <a (click)="onLogout()" class="nav-link-item logout-item">
        <i class="bi bi-box-arrow-left"></i> Quitter la session
      </a>
    </nav>
  </aside>

  <!-- 💻 ZONE DE CONTENU PRINCIPALE DYNAMIQUE -->
  <main class="app-main">
    <header class="app-header">
      <div class="header-welcome">
        <h2>Bienvenue, <span class="highlight">{{ recruiterName }}</span> 👋</h2>
        <p>Voici l'état actuel de vos campagnes de recrutement en Tunisie.</p>
      </div>

