              </div>
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Adresse e-mail :</span> 
                <span class="info-value">{{ selectedDirectCandidate.email }}</span>
              </div>
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Numéro de téléphone :</span> 
                <span class="info-value">{{ selectedDirectCandidate.phone || 'Non renseigné' }}</span>
              </div>
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Ville / Région :</span> 
                <span class="info-value">{{ selectedDirectCandidate.address || 'Non spécifiée' }}</span>
              </div>
            </div>
          </div>
          
          <!-- Boîte du Résumé (Inchangée et conservée à l'identique) -->
          <div class="summary-box" style="margin-top: 15px; padding: 16px; background: #f8fafc; border-radius: 8px; border-left: 4px solid #0ea5e9;">
            <span class="summary-title" style="color: #0f172a; font-weight: 700; font-size: 13px; display: block; margin-bottom: 8px;">
              Résumé du profil & Compétences clés
            </span>
            <p class="summary-text" style="margin: 0; color: #475569; font-size: 13px; line-height: 1.6; white-space: pre-line;">
              {{ selectedDirectCandidate.cv_summary || "Le candidat n'a pas encore rédigé de présentation de profil sur son espace TunJob." }}
            </p>
          </div>
        </div>

        <!-- 🔘 PIED DE PAGE : STRUCTURE FLEXBOX POUR UN ALIGNEMENT PARFAIT -->
        <div class="modal-footer" style="display: flex !important; align-items: center !important; justify-content: space-between !important; gap: 20px !important; margin-top: 25px; border-top: 1px solid #f1f5f9; padding-top: 16px; width: 100% !important; box-sizing: border-box !important;">
          
          <!-- 🟢 Groupe des 4 boutons de décision (Alignés à gauche) -->
          <div style="display: flex !important; gap: 8px !important; flex-wrap: wrap !important; flex-grow: 1 !important;">
            <button (click)="changeCandidateStatus(selectedDirectCandidate.application_id, 'Proposition')" style="background: #10b981; color: white; border: none; padding: 8px 12px; border-radius: 5px; font-size: 12px; font-weight: 600; cursor: pointer; display: flex; align-items: center; gap: 5px;">
              <svg xmlns="http://w3.org" width="12" height="12" fill="currentColor" viewBox="0 0 16 16"><path d="M16 8A8 8 0 1 1 0 8a8 8 0 0 1 16 0m-3.97-3.03a.75.75 0 0 0-1.08.022L7.477 9.417 5.384 7.323a.75.75 0 0 0-1.06 1.06L6.97 11.03a.75.75 0 0 0 1.079-.02l3.992-4.99a.75.75 0 0 0-.01-1.05z"/></svg>
              Accepter
            </button>
            
            <button (click)="changeCandidateStatus(selectedDirectCandidate.application_id, 'Nouveau')" style="background: #64748b; color: white; border: none; padding: 8px 12px; border-radius: 5px; font-size: 12px; font-weight: 600; cursor: pointer; display: flex; align-items: center; gap: 5px;">
              <svg xmlns="http://w3.org" width="12" height="12" fill="currentColor" viewBox="0 0 16 16"><path d="M8 15A7 7 0 1 1 8 1a7 7 0 0 0 0 14m0 1A8 8 0 1 0 8 0a8 8 0 0 0 0 16"/><path d="M5 6.25a1.25 1.25 0 1 1 2.5 0v3.5a1.25 1.25 0 1 1-2.5 0zm4 0a1.25 1.25 0 1 1 2.5 0v3.5a1.25 1.25 0 1 1-2.5 0z"/></svg>
              En attente
            </button>
            
            <button (click)="changeCandidateStatus(selectedDirectCandidate.application_id, 'Entretien')" style="background: #f97316; color: white; border: none; padding: 8px 12px; border-radius: 5px; font-size: 12px; font-weight: 600; cursor: pointer; display: flex; align-items: center; gap: 5px;">
              <svg xmlns="http://w3.org" width="12" height="12" fill="currentColor" viewBox="0 0 16 16"><path d="M8 16A8 8 0 1 0 8 0a8 8 0 0 0 0 16m7-8A7 7 0 1 1 1 8a7 7 0 0 1 14 0m-8.5-4.5A.5.5 0 0 1 7 4v3.5h2.5a.5.5 0 0 1 0 1H6.5a.5.5 0 0 1-.5-.5V4a.5.5 0 0 1 .5-.5"/></svg>
              Entretien
            </button>
            
            <button (click)="changeCandidateStatus(selectedDirectCandidate.application_id, 'Rejete')" style="background: #ef4444; color: white; border: none; padding: 8px 12px; border-radius: 5px; font-size: 12px; font-weight: 600; cursor: pointer; display: flex; align-items: center; gap: 5px;">
              <svg xmlns="http://w3.org" width="12" height="12" fill="currentColor" viewBox="0 0 16 16"><path d="M16 8A8 8 0 1 1 0 8a8 8 0 0 1 16 0M5.354 4.646a.5.5 0 1 0-.708.708L7.293 8l-2.647 2.646a.5.5 0 0 0 .708.708L8 8.707l2.646 2.647a.5.5 0 0 0 .708-.708L8.707 8l2.647-2.646a.5.5 0 0 0-.708-.708L8 7.293z"/></svg>
              Rejeter
            </button>
          </div>

          <!-- 🔴 Bouton Fermer (Isolé et poussé proprement tout à droite) -->
          <button class="btn-secondary" (click)="closeModal()" style="padding: 8px 16px !important; font-size: 12px !important; font-weight: 600 !important; cursor: pointer !important; flex-shrink: 0 !important; margin: 0 !important;">
            Fermer
          </button>
        </div>

    </div>
  </div>
</div>
